-- ============================================================
-- CNTP Production Capture - Master inventory (from Acumatica IN-StockItem export)
-- Run in: Supabase SQL Editor (staging first, then production)
-- 630 items. Re-runnable (upsert).
-- ============================================================

CREATE TABLE IF NOT EXISTS production.inventory_items (
  inventory_id   text PRIMARY KEY,
  description    text,
  item_class     text,
  category_code  text,
  product_group  text,
  grade          text,
  qc_grade       text,
  variant        text,
  base_unit      text,
  item_status    text,
  active         boolean NOT NULL DEFAULT true,
  created_at     timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS inventory_items_class_idx   ON production.inventory_items(item_class);
CREATE INDEX IF NOT EXISTS inventory_items_variant_idx ON production.inventory_items(variant);
CREATE INDEX IF NOT EXISTS inventory_items_group_idx   ON production.inventory_items(product_group);

GRANT USAGE ON SCHEMA production TO authenticated, service_role;
GRANT ALL ON production.inventory_items TO authenticated, service_role;
ALTER TABLE production.inventory_items ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS auth_all_inventory_items ON production.inventory_items;
CREATE POLICY auth_all_inventory_items ON production.inventory_items FOR ALL TO authenticated USING (true) WITH CHECK (true);

ON CONFLICT (inventory_id) DO UPDATE SET
  description=EXCLUDED.description, item_class=EXCLUDED.item_class,
  category_code=EXCLUDED.category_code, product_group=EXCLUDED.product_group,
  grade=EXCLUDED.grade, qc_grade=EXCLUDED.qc_grade, variant=EXCLUDED.variant,
  base_unit=EXCLUDED.base_unit, item_status=EXCLUDED.item_status;
